#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#include <stdbool.h>

#define MAX_LINE 1024
#define MAX_KEYS 200

typedef struct {
    char *key;
    char *value;
} Pair;

typedef struct {
    Pair *pairs;
    int cnt;
} Record;

// Trim leading and trailing spaces
static void trim(char *s) {
    while(*s && (*s==' '||*s=='\t' || *s=='\n' || *s=='\r')) s++;
    char *end = s + strlen(s) - 1;
    while(end> s && (*end==' '||*end=='\t' || *end=='\n' || *end=='\r')) *end--='\0';
    memmove(s- (s - (char*)s), s, strlen(s)+1);
}

static char* strip_quotes(char *s) {
    int len = strlen(s);
    if(len>=2 && s[0]=='\"' && s[len-1]=='\"') {
        s[len-1]='\0';
        return s+1;
    }
    return s;
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        getchar(); // consume newline
        Record *records = (Record*)malloc(N * sizeof(Record));
        char *header[MAX_KEYS];
        int headerCnt = 0;
        for(int i=0;i<N;i++){
            char line[MAX_LINE];
            fgets(line, sizeof(line), stdin);
            // remove trailing newline
            line[strcspn(line, "\n")] = '\0';
            // strip outer braces
            char *p = line;
            while(*p && *p!='{') p++;
            if(*p=='{') p++;
            char *end = strrchr(p, '}');
            if(end) *end='\0';
            // split by commas
            Record rec; rec.cnt=0; rec.pairs=NULL;
            char *token = strtok(p, ",");
            while(token){
                char *colon = strchr(token, ':');
                if(colon){
                    *colon='\0';
                    char *key = strip_quotes(token);
                    char *val = strip_quotes(colon+1);
                    // store in record
                    rec.pairs = (Pair*)realloc(rec.pairs, (rec.cnt+1)*sizeof(Pair));
                    rec.pairs[rec.cnt].key = strdup(key);
                    rec.pairs[rec.cnt].value = strdup(val);
                    rec.cnt++;
                    // header handling
                    bool found=false;
                    for(int h=0;h<headerCnt;h++) if(strcmp(header[h], key)==0){found=true;break;}
                    if(!found){
                        header[headerCnt++] = strdup(key);
                    }
                }
                token = strtok(NULL, ",");
            }
            records[i]=rec;
        }
        // output header
        for(int h=0;h<headerCnt;h++){
            if(h) printf(",");
            printf("%s", header[h]);
        }
        printf("\n");
        // output rows
        for(int i=0;i<N;i++){
            for(int h=0;h<headerCnt;h++){
                if(h) printf(",");
                // find value for header[h]
                const char *val="";
                for(int k=0;k<records[i].cnt;k++){
                    if(strcmp(records[i].pairs[k].key, header[h])==0){
                        val = records[i].pairs[k].value;
                        break;
                    }
                }
                printf("%s", val);
            }
            printf("\n");
        }
        if(T) printf("\n");
        // free memory
        for(int i=0;i<N;i++){
            for(int k=0;k<records[i].cnt;k++){
                free(records[i].pairs[k].key);
                free(records[i].pairs[k].value);
            }
            free(records[i].pairs);
        }
        free(records);
        for(int h=0;h<headerCnt;h++) free(header[h]);
    }
    return 0;
}

