        int N; cin>>N; string dummy; getline(cin,dummy); // consume endline
        vector<unordered_map<string,string>> records(N);
        vector<string> header;
        unordered_set<string> seen;
        for(int i=0;i<N;i++){
            string line; getline(cin,line);
            // remove outer braces
            size_t l=line.find('{'); size_t r=line.rfind('}');
            if(l!=string::npos && r!=string::npos && r>l) line=line.substr(l+1,r-l-1);
            stringstream ss(line);
            string token;
            while(getline(ss, token, ',')){
                size_t pos=token.find(':');
                if(pos==string::npos) continue;
                string key=token.substr(0,pos);
                string val=token.substr(pos+1);
                // strip quotes
                auto strip=[](string &s){
                    if(s.size()>=2 && s.front()=='\"' && s.back()=='\"') s=s.substr(1,s.size()-2);
                };
                strip(key); strip(val);
                records[i][key]=val;
                if(seen.insert(key).second) header.push_back(key);
            }
        }
        // output header
        for(size_t i=0;i<header.size();i++){
            if(i) cout<<',';
            cout<<header[i];
        }
        cout<<'\n';
        // output rows
        for(const auto &rec: records){
            for(size_t i=0;i<header.size();i++){
                if(i) cout<<',';
                auto it=rec.find(header[i]);
                if(it!=rec.end()) cout<<it->second;
            }
            cout<<'\n';
        }
        if(T) cout<<'\n';
    }
    return 0;
