import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            int N = Integer.parseInt(br.readLine().trim());
            List<Map<String, String>> records = new ArrayList<>();
            List<String> header = new ArrayList<>();
            Set<String> seen = new HashSet<>();
            for (int i = 0; i < N; i++) {
                String line = br.readLine();
                int l = line.indexOf('{');
                int r = line.lastIndexOf('}');
                if (l != -1 && r != -1 && r > l) line = line.substring(l + 1, r);
                Map<String, String> map = new HashMap<>();
                String[] parts = line.split(",");
                for (String part : parts) {
                    if (part.isEmpty()) continue;
                    int colon = part.indexOf(':');
                    if (colon == -1) continue;
                    String key = part.substring(0, colon).trim();
                    String val = part.substring(colon + 1).trim();
                    key = stripQuotes(key);
                    val = stripQuotes(val);
                    map.put(key, val);
                    if (seen.add(key)) header.add(key);
                }
                records.add(map);
            }
            // header line
            for (int i = 0; i < header.size(); i++) {
                if (i > 0) out.append(',');
                out.append(header.get(i));
            }
            out.append('\n');
            // rows
            for (Map<String, String> rec : records) {
                for (int i = 0; i < header.size(); i++) {
                    if (i > 0) out.append(',');
                    String v = rec.get(header.get(i));
                    if (v != null) out.append(v);
                }
                out.append('\n');
            }
            if (tc != T - 1) out.append('\n');
        }
        System.out.print(out.toString());
    }

    private static String stripQuotes(String s) {
        if (s.length() >= 2 && s.charAt(0) == '\"' && s.charAt(s.length() - 1) == '\"') {
            return s.substring(1, s.length() - 1);
        }
        return s;
    }
}

