#!/usr/bin/env python3
import sys, json

def parse_flat(line: str):
    # json.loads works for flat objects with proper quoting
    return json.loads(line)

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    idx = 0
    T = int(data[idx].strip()); idx += 1
    out_lines = []
    for _ in range(T):
        N = int(data[idx].strip()); idx += 1
        records = []
        header = []
        seen = set()
        for _ in range(N):
            line = data[idx].strip(); idx += 1
            obj = parse_flat(line)
            records.append(obj)
            for k in obj.keys():
                if k not in seen:
                    seen.add(k)
                    header.append(k)
        out_lines.append(','.join(header))
        for rec in records:
            row = [rec.get(col, '') for col in header]
            out_lines.append(','.join(row))
        if _ != T-1:
            out_lines.append('')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

